<?phpclass Po_model extends CI_Model {		public function add($data) {		$this->db->trans_start();        $this->db->insert('po',$data);		$insert_id = $this->db->insert_id();		$this->db->trans_complete();		return $insert_id;    }		public function update($data) {		$array = array('id'=>$data['id']);		$this->db->where($array)->update('po', $data);	}    	public function record_count() {        return $this->db->count_all('po');    }	public function getall() {		$query = $this->db->order_by('tanggal', 'desc')->get('po');				if ($query->num_rows() > 0)			return $query->result_array();		else			return 0;	}		public function getbycustomer($id) {		$query = $this->db->where('id_customer', $id)->get('po');				if ($query->num_rows() > 0)			return $query->result_array();		else			return 0;	}	public function get($id) {		$query = $this->db->where('id', $id)->get('po', 1, 0);		if ($query->num_rows() > 0)			return $query->result_array();		else			return 0;	}		public function laporan_po($tgl1 = null, $tgl2 = null) {		$query = $this->db->query("select * from po where tanggal>='".$tgl1."' and tanggal<='".$tgl2."'");		if ($query->num_rows() > 0)			return $query->result_array();		else			return 0;	}}